/// Simulates input handling with submit deduplication.
pub struct InputHandler {
    last_submitted_text: Option<String>,
    agent_running: bool,
}

impl InputHandler {
    pub fn new() -> Self {
        Self {
            last_submitted_text: None,
            agent_running: false,
        }
    }

    /// Handle submit with deduplication.
    /// Returns true if message was submitted, false if blocked.
    pub fn handle_submit(&mut self, text: &str) -> SubmitResult {
        // Block if agent already running
        if self.agent_running {
            return SubmitResult::Blocked {
                reason: "Agent already running".to_string(),
            };
        }

        // Block duplicate submission
        if self.last_submitted_text.as_ref() == Some(&text.to_string()) {
            return SubmitResult::Blocked {
                reason: "Duplicate submission".to_string(),
            };
        }

        // Submit
        self.last_submitted_text = Some(text.to_string());
        self.agent_running = true;
        SubmitResult::Submitted
    }

    pub fn agent_complete(&mut self) {
        self.agent_running = false;
    }
}

pub enum SubmitResult {
    Submitted,
    Blocked { reason: String },
}
